//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  //필수입력항목 체크
  if (!(await $c.gus.cfValidate($p, [ica_spplyDt, ed_summary]))) {
    return;
  }

  //수금 내역 금액 검증
  //if (!f_chkAmt()){
  //	await $c.gus.cfAlertMsg("수금정보의 금액항목 오류입니다.\n다시 확인하십시오.");
  //	return;
  //}

  if (!(await $c.win.confirm($p, MSG_CM_CRM_001))) return;
  if (ds_sellingEvidence.getCellData(0, "setoffSlipNo") != "") {
    await $c.gus.cfAlertMsg($p, "상계전표번호가 존재합니다. 상계 취소 후 다시 작업하여 주십시오.");
    return;
  }

  // Save or Del DataSet Setting
  await scwin.f_SetDataSet();

  //alert(ds_sellingEvidenceSave.getCellData(0, "costItemCd"));

  ds_sellingEvidenceSave.modifyRowStatus(0, "U");
  $c.sbm.execute($p, sbm_createDnTaxInvoice);
};

